"use client"

import { useEffect, useState } from "react"
import { useParams } from "next/navigation"
import {
  AlertCircle,
  CheckCircle2,
  Circle,
  Loader2,
  Plus,
  Trash2,
  Edit2,
  Filter,
  Search,
} from "lucide-react"

interface Task {
  _id: string
  category: string
  title: string
  description?: string
  completed: boolean
  priority: "LOW" | "MEDIUM" | "HIGH" | "CRITICAL"
  assignedContractor?: any
  dueDate?: string
  estimatedHours?: number
  actualHours?: number
  inspectionRequired: boolean
  inspectionPassed?: boolean
}

export default function TasksManager() {
  const params = useParams()
  const workspaceId = params?.propertyId as string

  const [tasks, setTasks] = useState<Task[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [filter, setFilter] = useState<"ALL" | "COMPLETED" | "PENDING">("ALL")
  const [categoryFilter, setCategoryFilter] = useState<string>("")
  const [searchTerm, setSearchTerm] = useState("")
  const [showForm, setShowForm] = useState(false)
  const [editingTask, setEditingTask] = useState<Task | null>(null)

  // Form state
  const [formData, setFormData] = useState({
    category: "DEMO",
    title: "",
    description: "",
    priority: "MEDIUM",
    dueDate: "",
    estimatedHours: 0,
  })

  // Fetch tasks
  useEffect(() => {
    if (!workspaceId) return

    const fetchTasks = async () => {
      try {
        setLoading(true)
        const query = new URLSearchParams({
          workspaceId: workspaceId,
          ...(categoryFilter && { category: categoryFilter }),
        })

        const res = await fetch(`/api/execution/tasks?${query}`)
        const result = await res.json()

        if (result.success) {
          setTasks(result.data)
        }
        setError(null)
      } catch (err) {
        setError(err instanceof Error ? err.message : "Failed to fetch tasks")
      } finally {
        setLoading(false)
      }
    }

    fetchTasks()
  }, [workspaceId, categoryFilter])

  // Create or update task
  const handleSaveTask = async () => {
    try {
      const url = editingTask
        ? `/api/execution/tasks/${editingTask._id}`
        : "/api/execution/tasks"

      const method = editingTask ? "PATCH" : "POST"

      const payload = editingTask
        ? formData
        : { executionWorkspaceId: workspaceId, ...formData }

      const res = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      })

      if (res.ok) {
        const result = await res.json()

        if (editingTask) {
          setTasks(tasks.map((t) => (t._id === editingTask._id ? result.data : t)))
        } else {
          setTasks([...tasks, result.data || result])
        }

        resetForm()
        setShowForm(false)
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to save task")
    }
  }

  // Toggle task completion
  const handleToggleComplete = async (taskId: string) => {
    try {
      const task = tasks.find((t) => t._id === taskId)
      if (!task) return

      const res = await fetch(`/api/execution/tasks/${taskId}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ completed: !task.completed }),
      })

      if (res.ok) {
        const result = await res.json()
        setTasks(tasks.map((t) => (t._id === taskId ? result.data : t)))
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to update task")
    }
  }

  // Delete task
  const handleDeleteTask = async (taskId: string) => {
    if (!confirm("Delete this task?")) return

    try {
      const res = await fetch(`/api/execution/tasks/${taskId}`, {
        method: "DELETE",
      })

      if (res.ok) {
        setTasks(tasks.filter((t) => t._id !== taskId))
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to delete task")
    }
  }

  const resetForm = () => {
    setFormData({
      category: "DEMO",
      title: "",
      description: "",
      priority: "MEDIUM",
      dueDate: "",
      estimatedHours: 0,
    })
    setEditingTask(null)
  }

  const startEdit = (task: Task) => {
    setEditingTask(task)
    setFormData({
      category: task.category,
      title: task.title,
      description: task.description || "",
      priority: task.priority,
      dueDate: task.dueDate ? task.dueDate.split("T")[0] : "",
      estimatedHours: task.estimatedHours || 0,
    })
    setShowForm(true)
  }

  // Filter tasks
  const filteredTasks = tasks.filter((task) => {
    if (filter === "COMPLETED" && !task.completed) return false
    if (filter === "PENDING" && task.completed) return false
    if (
      searchTerm &&
      !task.title.toLowerCase().includes(searchTerm.toLowerCase())
    )
      return false
    return true
  })

  const completedCount = tasks.filter((t) => t.completed).length
  const completionPercentage = tasks.length > 0 ? (completedCount / tasks.length) * 100 : 0

  const priorityColors = {
    LOW: "bg-blue-100 text-blue-700",
    MEDIUM: "bg-yellow-100 text-yellow-700",
    HIGH: "bg-orange-100 text-orange-700",
    CRITICAL: "bg-red-100 text-red-700",
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center py-12">
        <Loader2 className="w-8 h-8 text-blue-600 animate-spin" />
      </div>
    )
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-gray-900 dark:text-gray-50">
            Execution Tasks
          </h2>
          <p className="text-sm text-gray-600 dark:text-gray-400 mt-1">
            {completedCount} of {tasks.length} tasks completed ({completionPercentage.toFixed(0)}%)
          </p>
        </div>
        <button
          onClick={() => {
            resetForm()
            setShowForm(true)
          }}
          className="px-4 py-2 bg-blue-600 text-white rounded-lg flex items-center gap-2 hover:bg-blue-700"
        >
          <Plus className="w-4 h-4" />
          New Task
        </button>
      </div>

      {/* Progress Bar */}
      <div className="w-full h-2 bg-gray-200 dark:bg-gray-700 rounded-full overflow-hidden">
        <div
          className="h-full bg-blue-600 transition-all"
          style={{ width: `${completionPercentage}%` }}
        />
      </div>

      {/* Error Alert */}
      {error && (
        <div className="p-4 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-lg flex items-center gap-2">
          <AlertCircle className="w-5 h-5 text-red-600" />
          <p className="text-red-700 dark:text-red-300">{error}</p>
        </div>
      )}

      {/* Filters */}
      <div className="flex flex-wrap gap-3">
        <div className="flex gap-2">
          {(["ALL", "COMPLETED", "PENDING"] as const).map((f) => (
            <button
              key={f}
              onClick={() => setFilter(f)}
              className={`px-3 py-1 rounded-lg text-sm font-medium transition-colors ${
                filter === f
                  ? "bg-blue-600 text-white"
                  : "bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-200"
              }`}
            >
              {f}
            </button>
          ))}
        </div>

        <input
          type="text"
          placeholder="Search tasks..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="px-3 py-1 border border-gray-300 dark:border-gray-600 rounded-lg text-sm bg-white dark:bg-gray-800 text-gray-900 dark:text-gray-50"
        />

        <select
          value={categoryFilter}
          onChange={(e) => setCategoryFilter(e.target.value)}
          className="px-3 py-1 border border-gray-300 dark:border-gray-600 rounded-lg text-sm bg-white dark:bg-gray-800 text-gray-900 dark:text-gray-50"
        >
          <option value="">All Categories</option>
          <option value="DEMO">Demo</option>
          <option value="WINDOWS">Windows</option>
          <option value="EXTERIOR">Exterior</option>
          <option value="INTERIOR">Interior</option>
          <option value="ELECTRICAL">Electrical</option>
          <option value="PLUMBING">Plumbing</option>
          <option value="HVAC">HVAC</option>
          <option value="KITCHEN">Kitchen</option>
          <option value="BATHROOMS">Bathrooms</option>
          <option value="ROOF">Roof</option>
          <option value="PERMITS">Permits</option>
          <option value="FINAL">Final</option>
        </select>
      </div>

      {/* Task Form */}
      {showForm && (
        <div className="p-6 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                Category
              </label>
              <select
                value={formData.category}
                onChange={(e) =>
                  setFormData({ ...formData, category: e.target.value })
                }
                className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-gray-50"
              >
                <option value="DEMO">Demo</option>
                <option value="WINDOWS">Windows</option>
                <option value="EXTERIOR">Exterior</option>
                <option value="INTERIOR">Interior</option>
                <option value="ELECTRICAL">Electrical</option>
                <option value="PLUMBING">Plumbing</option>
                <option value="HVAC">HVAC</option>
                <option value="KITCHEN">Kitchen</option>
                <option value="BATHROOMS">Bathrooms</option>
                <option value="ROOF">Roof</option>
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                Priority
              </label>
              <select
                value={formData.priority}
                onChange={(e) =>
                  setFormData({ ...formData, priority: e.target.value })
                }
                className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-gray-50"
              >
                <option value="LOW">Low</option>
                <option value="MEDIUM">Medium</option>
                <option value="HIGH">High</option>
                <option value="CRITICAL">Critical</option>
              </select>
            </div>

            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                Title
              </label>
              <input
                type="text"
                value={formData.title}
                onChange={(e) =>
                  setFormData({ ...formData, title: e.target.value })
                }
                placeholder="Task title"
                className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-gray-50"
              />
            </div>

            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                Description
              </label>
              <textarea
                value={formData.description}
                onChange={(e) =>
                  setFormData({ ...formData, description: e.target.value })
                }
                placeholder="Task description"
                rows={3}
                className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-gray-50"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                Due Date
              </label>
              <input
                type="date"
                value={formData.dueDate}
                onChange={(e) =>
                  setFormData({ ...formData, dueDate: e.target.value })
                }
                className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-gray-50"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                Estimated Hours
              </label>
              <input
                type="number"
                value={formData.estimatedHours}
                onChange={(e) =>
                  setFormData({
                    ...formData,
                    estimatedHours: Number(e.target.value),
                  })
                }
                className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-gray-50"
              />
            </div>
          </div>

          <div className="flex gap-2 justify-end">
            <button
              onClick={() => {
                setShowForm(false)
                resetForm()
              }}
              className="px-4 py-2 bg-gray-200 dark:bg-gray-700 text-gray-900 dark:text-gray-50 rounded-lg hover:bg-gray-300 dark:hover:bg-gray-600"
            >
              Cancel
            </button>
            <button
              onClick={handleSaveTask}
              className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
            >
              {editingTask ? "Update" : "Create"} Task
            </button>
          </div>
        </div>
      )}

      {/* Tasks List */}
      <div className="space-y-2">
        {filteredTasks.length === 0 ? (
          <div className="text-center py-12">
            <p className="text-gray-600 dark:text-gray-400">
              {filter === "ALL" ? "No tasks yet" : `No ${filter.toLowerCase()} tasks`}
            </p>
          </div>
        ) : (
          filteredTasks.map((task) => (
            <div
              key={task._id}
              className="p-4 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg hover:border-gray-300 dark:hover:border-gray-600 transition-colors"
            >
              <div className="flex items-start gap-4">
                <button
                  onClick={() => handleToggleComplete(task._id)}
                  className="mt-1 flex-shrink-0"
                >
                  {task.completed ? (
                    <CheckCircle2 className="w-6 h-6 text-emerald-600" />
                  ) : (
                    <Circle className="w-6 h-6 text-gray-400" />
                  )}
                </button>

                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 flex-wrap">
                    <h3
                      className={`font-medium ${
                        task.completed
                          ? "text-gray-400 line-through"
                          : "text-gray-900 dark:text-gray-50"
                      }`}
                    >
                      {task.title}
                    </h3>
                    <span className={`px-2 py-1 rounded text-xs font-medium ${priorityColors[task.priority]}`}>
                      {task.priority}
                    </span>
                    <span className="px-2 py-1 rounded text-xs font-medium bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300">
                      {task.category}
                    </span>
                  </div>

                  {task.description && (
                    <p className="text-sm text-gray-600 dark:text-gray-400 mt-1">
                      {task.description}
                    </p>
                  )}

                  {task.dueDate && (
                    <p className="text-xs text-gray-500 dark:text-gray-400 mt-2">
                      Due: {new Date(task.dueDate).toLocaleDateString()}
                    </p>
                  )}
                </div>

                <div className="flex gap-1 flex-shrink-0">
                  <button
                    onClick={() => startEdit(task)}
                    className="p-2 text-blue-600 dark:text-blue-400 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded"
                  >
                    <Edit2 className="w-4 h-4" />
                  </button>
                  <button
                    onClick={() => handleDeleteTask(task._id)}
                    className="p-2 text-red-600 dark:text-red-400 hover:bg-red-50 dark:hover:bg-red-900/20 rounded"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  )
}
